#!/usr/bin/env bash
# multithread-the-buying-committee.sh — Multithread the buying committee（多线程触达买方委员会） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Multithread the buying committee（多线程触达买方委员会）"

usage() {
  cat <<EOF
multithread-the-buying-committee.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./multithread-the-buying-committee.sh             # interactive
  ./multithread-the-buying-committee.sh --dry-run
  ./multithread-the-buying-committee.sh --json
  ./multithread-the-buying-committee.sh --explain
  ./multithread-the-buying-committee.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Multithread the buying committee（多线程触达买方委员会）" 工作流。

一句话: Engage the 6-10 stakeholders who actually decide — in parallel — instead of betting the deal on a single champion. A cross-cutting motion woven through discovery → qualify → close; the single biggest structural difference between junior and senior deals. (evidence: [T03-S028, T03-S029])

入门 SOP 共 4 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Map the buying committee** — identify the roles: Economic Buyer, User Buyer(s), Technical Buyer, Champion, Coach, Blocker(s). (evidence: [T03-S028])"
  "**Engage beyond the first contact** — proactively reach the other stakeholders (often via the champion / a multithread-ask in discovery). (evidence: [T03-S028])"
  "**Tailor the message per stakeholder** — EB hears business value, technical buyer hears validation, user buyer hears day-to-day impact. (evidence: [T03-S016])"
  "**Build internal consensus via a Mobilizer** — find the stakeholder willing to challenge the status quo and drive alignment, not just the friendly \"Talker.\" (evidence: [T03-S029])"
)
declare -a FAILURE_MODES=(
  "**Single-threaded deal — relying on one champion/contact**: if they leave or go cold, the deal dies. Avoid: map the full committee and engage ≥3 stakeholders in parallel. (evidence: [T03-S028])"
  "**Selling to \"the decision maker\" (singular)**: enterprise B2B has a 6-10-person committee, no single buyer. Avoid: map and multithread the whole group. (evidence: [T03-S029])"
  "**Chasing the friendly Talker instead of the Mobilizer**: the agreeable contact who won't drive change produces no internal momentum. Avoid: find the stakeholder willing to challenge the status quo and build consensus. (evidence: [T03-S029])"
  "**Avoiding blockers until they surface late**: an un-engaged blocker can veto at the finish line. Avoid: engage blockers early — they can flip to champions if won. (evidence: [T03-S028])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "multithread-the-buying-committee-walkthrough"
fi
